import{_ as e,o as d,c,a0 as t}from"./chunks/framework.jwovEGr5.js";const T=JSON.parse('{"title":"정보처리기사 SQL 기출 요약","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/project/정보처리기사-실기/정보처리기사-SQL-기출-요약.md","filePath":"outta-space/project/정보처리기사-실기/정보처리기사-SQL-기출-요약.md"}'),r={name:"outta-space/project/정보처리기사-실기/정보처리기사-SQL-기출-요약.md"};function l(a,o,i,n,s,E){return d(),c("div",null,[...o[0]||(o[0]=[t('<h1 id="정보처리기사-sql-기출-요약" tabindex="-1">정보처리기사 SQL 기출 요약 <a class="header-anchor" href="#정보처리기사-sql-기출-요약" aria-label="Permalink to &quot;정보처리기사 SQL 기출 요약&quot;">​</a></h1><h2 id="결과-추론" tabindex="-1">결과 추론 <a class="header-anchor" href="#결과-추론" aria-label="Permalink to &quot;결과 추론&quot;">​</a></h2><h3 id="count-distinct-on-delete-cascade" tabindex="-1"><code>COUNT</code>, <code>DISTINCT</code>, <code>ON DELETE CASCADE</code> <a class="header-anchor" href="#count-distinct-on-delete-cascade" aria-label="Permalink to &quot;`COUNT`, `DISTINCT`, `ON DELETE CASCADE`&quot;">​</a></h3><ul><li><strong>유형:</strong> 집계 함수, 중복 제거, 외래키의 연쇄 삭제 결과 추론</li><li><strong>규칙:</strong> <code>COUNT(컬럼명)</code>은 <code>NULL</code>이 아닌 값의 개수를 세고, <code>ON DELETE CASCADE</code>는 부모 행 삭제 시 자식 행도 함께 삭제한다.</li><li><strong>함정:</strong> <code>SELECT DISTINCT COUNT(컬럼)</code>은 <code>COUNT(DISTINCT 컬럼)</code>과 다르다.</li><li><strong>예시:</strong> 부서 코드가 20인 직원 3명 → <code>COUNT</code> 결과 3 → 부서 코드 20 삭제 후 직원 3명도 삭제 → 남은 직원 4명</li></ul><h3 id="select-distinct와-count-distinct" tabindex="-1"><code>SELECT DISTINCT</code>와 <code>COUNT(DISTINCT)</code> <a class="header-anchor" href="#select-distinct와-count-distinct" aria-label="Permalink to &quot;`SELECT DISTINCT`와 `COUNT(DISTINCT)`&quot;">​</a></h3><ul><li><strong>유형:</strong> 조회 결과의 튜플 수, 중복 제거 결과 추론</li><li><strong>규칙:</strong> <code>DISTINCT</code>는 중복값을 제거하고, <code>COUNT(DISTINCT DEPT)</code>는 조건에 맞는 행에서 서로 다른 학과 값의 개수를 센다.</li><li><strong>함정:</strong> <code>SELECT DEPT</code>는 전체 학생 수만큼 200행이 나오지만, <code>SELECT DISTINCT DEPT</code>는 학과 종류인 전기과·전산과·전자과 3행만 나온다.</li><li><strong>예시:</strong> 전기과 50명 + 전산과 100명 + 전자과 50명 → <code>SELECT DEPT</code>는 200행, <code>SELECT DISTINCT DEPT</code>는 3행, <code>WHERE DEPT = &#39;전산과&#39;</code>에서 <code>COUNT(DISTINCT DEPT)</code>는 1</li></ul><h3 id="다중-행-서브쿼리와-all" tabindex="-1">다중 행 서브쿼리와 <code>ALL</code> <a class="header-anchor" href="#다중-행-서브쿼리와-all" aria-label="Permalink to &quot;다중 행 서브쿼리와 `ALL`&quot;">​</a></h3><ul><li><strong>유형:</strong> 다중 행 서브쿼리, <code>ALL</code> 비교 연산자</li><li><strong>규칙:</strong> <code>&gt; ALL(서브쿼리)</code>은 서브쿼리 결과의 모든 값보다 커야 한다는 뜻이다.</li><li><strong>함정:</strong> <code>MAX(단가)</code>와 논리 결과는 비슷할 수 있지만, 빈칸이 집계 함수 자리가 아니라면 <code>ALL</code>, <code>ANY</code>, <code>SOME</code>과 같은 비교 한정자를 써야 한다.</li><li><strong>예시:</strong> <code>단가 &gt; ALL(1000, 2000, 3000)</code>은 <code>단가 &gt; 3000</code>과 같은 의미다.</li></ul><h3 id="count-컬럼-과-null" tabindex="-1"><code>COUNT(컬럼)</code>과 <code>NULL</code> <a class="header-anchor" href="#count-컬럼-과-null" aria-label="Permalink to &quot;`COUNT(컬럼)`과 `NULL`&quot;">​</a></h3><ul><li><strong>유형:</strong> <code>COUNT(컬럼)</code>, <code>IN</code>, <code>OR</code>, <code>NULL</code> 제외 여부</li><li><strong>규칙:</strong> <code>COUNT(COL2)</code>는 조건을 만족하는 행 중 <code>COL2</code>가 <code>NULL</code>이 아닌 행만 센다.</li><li><strong>함정:</strong> <code>WHERE</code> 조건에 맞는 행이 1·3·5번이어도 1번의 <code>COL2</code>가 <code>NULL</code>이면 집계에서 제외된다.</li><li><strong>예시:</strong> <code>COL1 IN (2, 3)</code> 또는 <code>COL2 IN (3, 5)</code>를 만족하는 행이 1번(<code>NULL</code>), 3번(5), 5번(3)이라면 <code>COUNT(COL2)</code>는 2다.</li></ul><h2 id="관계-대수" tabindex="-1">관계 대수 <a class="header-anchor" href="#관계-대수" aria-label="Permalink to &quot;관계 대수&quot;">​</a></h2><h3 id="프로젝트-projection" tabindex="-1">프로젝트(Projection) <a class="header-anchor" href="#프로젝트-projection" aria-label="Permalink to &quot;프로젝트(Projection)&quot;">​</a></h3><ul><li><strong>유형:</strong> 프로젝트 연산 결과 추론</li><li><strong>규칙:</strong> <code>π속성명(릴레이션)</code>은 지정한 속성만 추출하므로 <code>πTTL(EMPLOYEE)</code>는 <code>TTL</code> 열만 출력한다.</li><li><strong>함정:</strong> 프로젝트는 행에 조건을 거는 연산이 아니라 열을 고르는 연산이므로 <code>AGE</code>, <code>INDEX</code>는 결과에서 제외된다.</li><li><strong>예시:</strong> <code>EMPLOYEE</code>에서 <code>TTL</code>만 추출 → <code>TTL</code>, 부장, 대리, 과장, 차장</li></ul><h2 id="데이터-조작-및-정의" tabindex="-1">데이터 조작 및 정의 <a class="header-anchor" href="#데이터-조작-및-정의" aria-label="Permalink to &quot;데이터 조작 및 정의&quot;">​</a></h2><h3 id="update" tabindex="-1"><code>UPDATE</code> <a class="header-anchor" href="#update" aria-label="Permalink to &quot;`UPDATE`&quot;">​</a></h3><ul><li><strong>유형:</strong> <code>UPDATE</code>의 주요 구성 요소</li><li><strong>규칙:</strong> <code>UPDATE</code>는 갱신 대상 테이블, <code>SET</code>은 변경할 열과 값, <code>WHERE</code>는 변경할 행의 조건을 지정한다.</li><li><strong>함정:</strong> <code>WHERE</code>가 없으면 모든 행이 변경된다. <code>SET</code>에는 여러 열을 지정할 수 있고, 조건에는 비교 연산자, <code>AND</code>, <code>OR</code>, <code>IN</code>, <code>BETWEEN</code> 등을 사용할 수 있다.</li><li><strong>예시:</strong> <code>UPDATE 학생 SET 학과 = &#39;컴퓨터공학과&#39;, 학년 = 3 WHERE 학번 = 1001;</code></li></ul><h3 id="delete" tabindex="-1"><code>DELETE</code> <a class="header-anchor" href="#delete" aria-label="Permalink to &quot;`DELETE`&quot;">​</a></h3><ul><li><strong>유형:</strong> <code>DELETE</code>의 기본 형식, 조건부 삭제, 문자열 조건</li><li><strong>규칙:</strong> <code>DELETE FROM 테이블명 WHERE 조건;</code> 형식으로 쓰며 문자열 값은 작은따옴표로 감싼다.</li><li><strong>함정:</strong> <code>DELETE</code> 뒤에는 열 이름이 아닌 <code>FROM 테이블명</code>을 쓴다. <code>WHERE</code>를 생략하면 테이블의 모든 행이 삭제된다.</li><li><strong>예시:</strong> <code>DELETE FROM 학생 WHERE 이름 = &#39;민수&#39;;</code></li></ul><h3 id="alter-table" tabindex="-1"><code>ALTER TABLE</code> <a class="header-anchor" href="#alter-table" aria-label="Permalink to &quot;`ALTER TABLE`&quot;">​</a></h3><ul><li><strong>유형:</strong> 열 추가, 테이블 구조 변경</li><li><strong>규칙:</strong> <code>ALTER TABLE 테이블명 ADD 컬럼명 데이터타입;</code> 형식으로 기존 테이블에 새 속성을 추가한다.</li><li><strong>함정:</strong> 데이터를 수정하는 <code>UPDATE</code>가 아니라 테이블 구조를 바꾸는 DDL이므로 <code>ALTER</code>를 써야 한다.</li><li><strong>예시:</strong> <code>ALTER TABLE 학생 ADD 주소 VARCHAR(20);</code></li></ul><h3 id="ddl" tabindex="-1">DDL <a class="header-anchor" href="#ddl" aria-label="Permalink to &quot;DDL&quot;">​</a></h3><ul><li><strong>유형:</strong> 테이블 구조의 정의·변경·삭제</li><li><strong>규칙:</strong> DDL은 데이터 자체가 아니라 데이터베이스 객체의 구조를 정의하며 대표적으로 <code>CREATE</code>, <code>ALTER</code>, <code>DROP</code>, <code>TRUNCATE</code>가 있다.</li><li><strong>함정:</strong> <code>INSERT</code>, <code>UPDATE</code>, <code>DELETE</code>는 데이터를 조작하는 DML이고, <code>CREATE</code>, <code>ALTER</code>, <code>DROP</code>은 구조를 다루는 DDL이다.</li><li><strong>예시:</strong> <code>CREATE TABLE 학생(학번 CHAR(10));</code> / <code>ALTER TABLE 학생 ADD 주소 VARCHAR(20);</code> / <code>DROP TABLE 학생;</code> / <code>TRUNCATE TABLE 학생;</code></li></ul><h2 id="조회와-정렬" tabindex="-1">조회와 정렬 <a class="header-anchor" href="#조회와-정렬" aria-label="Permalink to &quot;조회와 정렬&quot;">​</a></h2><h3 id="where-in" tabindex="-1"><code>WHERE IN</code> <a class="header-anchor" href="#where-in" aria-label="Permalink to &quot;`WHERE IN`&quot;">​</a></h3><ul><li><strong>유형:</strong> 열 조회, <code>WHERE</code> 조건, <code>IN</code> 연산자</li><li><strong>규칙:</strong> <code>IN (값1, 값2)</code>는 열 값이 괄호 안의 값 중 하나와 일치하는 행을 조회한다.</li><li><strong>함정:</strong> 학년이 숫자 자료형이면 3과 4에 작은따옴표를 붙이지 않는다. 조회할 열은 문제에서 요구한 학번과 이름만 쓴다.</li><li><strong>예시:</strong> <code>SELECT 학번, 이름 FROM 학생 WHERE 학년 IN (3, 4);</code></li></ul><h3 id="order-by" tabindex="-1"><code>ORDER BY</code> <a class="header-anchor" href="#order-by" aria-label="Permalink to &quot;`ORDER BY`&quot;">​</a></h3><ul><li><strong>유형:</strong> 특정 열을 기준으로 한 내림차순 정렬</li><li><strong>규칙:</strong> <code>ORDER BY 컬럼명 ASC|DESC</code> 형식으로 정렬한다. <code>ASC</code>는 오름차순, <code>DESC</code>는 내림차순이다.</li><li><strong>함정:</strong> 조회할 열과 정렬 기준 열을 구분해야 한다. 점수 기준 내림차순이라면 <code>ORDER BY score DESC</code>를 사용한다.</li><li><strong>예시:</strong> <code>SELECT name, score FROM 성적 ORDER BY score DESC;</code></li></ul><h3 id="like와-order-by" tabindex="-1"><code>LIKE</code>와 <code>ORDER BY</code> <a class="header-anchor" href="#like와-order-by" aria-label="Permalink to &quot;`LIKE`와 `ORDER BY`&quot;">​</a></h3><ul><li><strong>유형:</strong> 문자열 패턴 검색, 내림차순 정렬</li><li><strong>규칙:</strong> <code>LIKE &#39;이%&#39;</code>는 이름이 ‘이’로 시작하는 값을 찾고, <code>ORDER BY 가입일 DESC</code>는 가입일을 기준으로 내림차순 정렬한다.</li><li><strong>함정:</strong> <code>GROUP BY</code>는 데이터를 묶는 절이다. 특정 글자로 시작하는 문자열 조건에는 <code>LIKE</code>를 써야 한다.</li><li><strong>예시:</strong> <code>SELECT * FROM 회원 WHERE 이름 LIKE &#39;이%&#39; ORDER BY 가입일 DESC;</code></li></ul><h2 id="그룹과-집계" tabindex="-1">그룹과 집계 <a class="header-anchor" href="#그룹과-집계" aria-label="Permalink to &quot;그룹과 집계&quot;">​</a></h2><h3 id="group-by와-count" tabindex="-1"><code>GROUP BY</code>와 <code>COUNT</code> <a class="header-anchor" href="#group-by와-count" aria-label="Permalink to &quot;`GROUP BY`와 `COUNT`&quot;">​</a></h3><ul><li><strong>유형:</strong> 그룹화, 집계 함수, 별칭</li><li><strong>규칙:</strong> <code>GROUP BY 학과</code>는 학과별로 행을 묶고, <code>COUNT(*)</code>는 각 학과의 튜플 수를 세며, <code>AS</code>는 출력 열 이름을 지정한다.</li><li><strong>함정:</strong> <code>AS 학과별튜플수</code>는 계산 조건이 아니라 <code>COUNT(*)</code> 결과 열의 별칭이다.</li><li><strong>예시:</strong> <code>SELECT 학과, COUNT(*) AS 학과별튜플수 FROM 학생 GROUP BY 학과;</code></li></ul><h3 id="group-by와-having" tabindex="-1"><code>GROUP BY</code>와 <code>HAVING</code> <a class="header-anchor" href="#group-by와-having" aria-label="Permalink to &quot;`GROUP BY`와 `HAVING`&quot;">​</a></h3><ul><li><strong>유형:</strong> 그룹화, 그룹 조건, <code>MIN</code>, <code>MAX</code>, <code>AVG</code>, 별칭</li><li><strong>규칙:</strong> <code>GROUP BY 과목이름</code>으로 과목별 그룹을 만들고, <code>HAVING AVG(점수) &gt;= 90</code>으로 평균이 90점 이상인 과목만 남긴다.</li><li><strong>함정:</strong> <code>WHERE</code>는 그룹화 전 개별 행의 조건이고, <code>HAVING</code>은 그룹화 후 집계 결과의 조건이다. 평균 점수 조건에는 <code>HAVING</code>을 써야 한다.</li><li><strong>예시:</strong> <code>SELECT 과목이름, MIN(점수) AS 최소점수, MAX(점수) AS 최대점수 FROM 성적 GROUP BY 과목이름 HAVING AVG(점수) &gt;= 90;</code></li></ul><h2 id="인덱스" tabindex="-1">인덱스 <a class="header-anchor" href="#인덱스" aria-label="Permalink to &quot;인덱스&quot;">​</a></h2><h3 id="create-index" tabindex="-1"><code>CREATE INDEX</code> <a class="header-anchor" href="#create-index" aria-label="Permalink to &quot;`CREATE INDEX`&quot;">​</a></h3><ul><li><strong>유형:</strong> 인덱스 생성, 검색 성능 향상</li><li><strong>규칙:</strong> <code>CREATE INDEX 인덱스명 ON 테이블명(컬럼명);</code> 형식으로 특정 열을 기준으로 한 검색용 자료 구조를 생성한다.</li><li><strong>함정:</strong> 인덱스를 생성해도 테이블의 행, 값, 출력 결과는 바뀌지 않는다. 검색을 빠르게 하기 위한 보조 구조만 추가된다.</li><li><strong>예시:</strong> <code>CREATE INDEX idx_name ON student(name);</code> 실행 후 <code>student</code> 테이블은 그대로이고, <code>name = &#39;brown&#39;</code>과 같은 조건 검색에서 <code>idx_name</code>을 이용할 수 있다.</li></ul><h3 id="주요-인덱스-명령" tabindex="-1">주요 인덱스 명령 <a class="header-anchor" href="#주요-인덱스-명령" aria-label="Permalink to &quot;주요 인덱스 명령&quot;">​</a></h3><ul><li><strong>일반 인덱스:</strong> 특정 열을 기준으로 검색 성능을 높인다. 예: <code>CREATE INDEX idx_name ON student(name);</code></li><li><strong>고유 인덱스:</strong> 중복값을 허용하지 않는다. 예: <code>CREATE UNIQUE INDEX idx_stid ON student(stid);</code></li><li><strong>인덱스 삭제:</strong> 생성된 인덱스를 삭제한다. 예: <code>DROP INDEX idx_name;</code></li><li><strong>복합 인덱스:</strong> 두 개 이상의 열을 묶어 생성한다. 예: <code>CREATE INDEX idx_name_score ON student(name, score);</code></li></ul><h2 id="조인" tabindex="-1">조인 <a class="header-anchor" href="#조인" aria-label="Permalink to &quot;조인&quot;">​</a></h2><h3 id="cross-join-결과-추론" tabindex="-1"><code>CROSS JOIN</code> 결과 추론 <a class="header-anchor" href="#cross-join-결과-추론" aria-label="Permalink to &quot;`CROSS JOIN` 결과 추론&quot;">​</a></h3><ul><li><strong>유형:</strong> 카티션 곱, <code>LIKE</code> 패턴 조건, 조인 후 <code>COUNT(*)</code> 결과 추론</li><li><strong>규칙:</strong> <code>CROSS JOIN</code>은 두 테이블의 모든 행 조합을 만든 뒤 <code>WHERE</code> 조건으로 필요한 조합만 필터링한다.</li><li><strong>함정:</strong> A 3행 × B 2행 = 6개 조합을 먼저 만들고, <code>A.NAME LIKE B.RULE</code>을 만족하는 조합만 센다.</li><li><strong>예시:</strong> Smith는 <code>S%</code>에 매칭, Scott은 <code>S%</code>에 매칭, Smith와 Scott은 <code>%T%</code>에도 각각 매칭 → 총 4개</li></ul><h3 id="조인-종류" tabindex="-1">조인 종류 <a class="header-anchor" href="#조인-종류" aria-label="Permalink to &quot;조인 종류&quot;">​</a></h3><ul><li><strong>CROSS JOIN:</strong> 조건 없이 두 테이블의 모든 조합을 만든다. 예: <code>SELECT * FROM A CROSS JOIN B;</code></li><li><strong>INNER JOIN:</strong> 조인 조건을 만족하는 행만 출력한다. 예: <code>SELECT * FROM A INNER JOIN B ON A.id = B.id;</code></li><li><strong>LEFT OUTER JOIN:</strong> 왼쪽 테이블은 모두 남기고 오른쪽 테이블은 조건에 맞는 행만 붙인다. 예: <code>SELECT * FROM A LEFT JOIN B ON A.id = B.id;</code></li><li><strong>RIGHT OUTER JOIN:</strong> 오른쪽 테이블은 모두 남기고 왼쪽 테이블은 조건에 맞는 행만 붙인다. 예: <code>SELECT * FROM A RIGHT JOIN B ON A.id = B.id;</code></li><li><strong>FULL OUTER JOIN:</strong> 양쪽 테이블의 모든 행을 남기고, 조건에 맞지 않는 부분은 <code>NULL</code>로 채운다. 예: <code>SELECT * FROM A FULL OUTER JOIN B ON A.id = B.id;</code></li><li><strong>SELF JOIN:</strong> 같은 테이블을 자기 자신과 조인한다. 예: <code>SELECT * FROM 직원 A JOIN 직원 B ON A.상사ID = B.직원ID;</code></li><li><strong>NATURAL JOIN:</strong> 두 테이블에서 이름이 같은 열을 기준으로 자동 조인한다. 예: <code>SELECT * FROM A NATURAL JOIN B;</code></li></ul>',44)])])}const h=e(r,[["render",l]]);export{T as __pageData,h as default};
